DROP TABLE IF EXISTS `orden_repara`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `orden_repara` (
  `Id` int(8) NOT NULL AUTO_INCREMENT,
  `or_num_orden` int(8) NOT NULL DEFAULT 0,
  `fecha_ingreso` datetime DEFAULT NULL,
  `fecha_egreso` datetime DEFAULT NULL COMMENT 'fecha y hora',
  `or_cod_cliente` int(5) NOT NULL DEFAULT 0,
  `or_nombre_cliente` varchar(45) NOT NULL DEFAULT '',
  `equ_ingresa` varchar(60) NOT NULL DEFAULT '' COMMENT 'Descripcion del equipo que ingresa, puede ser pc, notebook, impresoras....',
  `equ_grupo` varchar(30) NOT NULL DEFAULT '' COMMENT 'grupo al que pertenece el equipo -- pc, notebooks, pantallas, impresoras, fuentes',
  `equ_procesador` varchar(30) NOT NULL DEFAULT '',
  `equ_ram` varchar(55) NOT NULL DEFAULT '',
  `equ_discos` varchar(50) NOT NULL DEFAULT '',
  `equ_sist_oper` varchar(30) NOT NULL DEFAULT '',
  `equ_obser` varchar(170) NOT NULL DEFAULT '' COMMENT 'Se utiliza para hacer alguna observacion sobre el equipo que ingresa a servicio tecnico',
  `equ_accesorios` varchar(55) NOT NULL DEFAULT '' COMMENT 'accesorios que acompañan al equipo, fuentes, pendrives, cables.....',
  `equ_estado` varchar(100) NOT NULL DEFAULT '' COMMENT 'En que estado inngresa al negocio: sucio sin bateria, bisagras rotas ....',
  `dat_ctaycontr` varchar(100) NOT NULL DEFAULT '' COMMENT 'cuentas y contraseñas que hagan falta para el trabajo',
  `dat_requerido` varchar(170) NOT NULL DEFAULT '' COMMENT 'requerimiento del cliente detalle de la falla',
  `inf_diagnostico` text NOT NULL COMMENT 'diagnostico post revision del tecnico',
  `inf_presupuesto` varchar(200) NOT NULL DEFAULT '' COMMENT 'presupuesto de reparacion',
  `trab_realizado` text NOT NULL COMMENT 'Detalle del trabajo que se realizo',
  `trab_partes` varchar(200) NOT NULL DEFAULT '' COMMENT 'partes que fueron reemplazadas',
  `trab_anotacion` text NOT NULL COMMENT 'para explayarse en los detalles del trabajo',
  `tot_mano_obra` float(14,2) NOT NULL DEFAULT 0.00 COMMENT 'importe a cobrar de mano de obra',
  `tot_partes` float(14,2) NOT NULL DEFAULT 0.00 COMMENT 'importe que suman las partes colocadas',
  `fin_retirada` varchar(1) NOT NULL DEFAULT '' COMMENT 'estado de retiro',
  PRIMARY KEY (`Id`)
) ENGINE=InnoDB AUTO_INCREMENT=735 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
